					if(!opts.qpro || length < 21) return;
					var id = blob.read_shift(1);
					blob.l += 17;
					blob.read_shift(1);
					blob.l += 2;
					var nm = blob.read_shift(length - 21, 'cstr');
					return [id, nm];
