				function parse_XFORMAT(blob, length) {
					var o = {}, tgt = blob.l + length;
					while(blob.l < tgt) {
						var dt = blob.read_shift(2);
						if(dt == 0x36b0) {
							o[dt] = [0, ""];
							o[dt][0] = blob.read_shift(2);
							while(blob[blob.l]) { o[dt][1] += String.fromCharCode(blob[blob.l]); blob.l++; } blob.l++;
						}
						// TODO: 0x3a99 ??
					}
					return o;
				}
